            // Companion slots
            const hasMag = hasMagneticPersonalityPerk();
            const bonus = hasMag ? 1 : 0;
            let slots, hcSlots;
            if (val >= 10) slots = 3;
            else if (val >= 7) slots = 2;
            else if (val >= 4) slots = 1;
